import { defineChannel, GET, POST } from "eve/channels";
import { toolResultFrom } from "eve/tools";
import { sendViaCallback, type WassistWebhookPayload } from "#lib/wassist";
import offerChoices from "../tools/offer_choices";
import generateMealVisual from "../tools/generate_meal_visual";

type QuickReplyButton = {
  type: "quick_reply";
  text: string;
  quickReplyId: string;
};

type WassistState = {
  phoneNumber: string | null;
  replyCallback: string | null;
  pendingButtons: QuickReplyButton[] | null;
  pendingImageUrl: string | null;
};

type WassistTarget = {
  phoneNumber: string;
};

type WassistCtx = {
  state: WassistState;
};

function tokenFor(phoneNumber: string) {
  return phoneNumber;
}

export default defineChannel<WassistState, WassistCtx, WassistTarget>({
  cors: true,
  state: {
    phoneNumber: null,
    replyCallback: null,
    pendingButtons: null,
    pendingImageUrl: null,
  },

  context(state) {
    return { state };
  },

  metadata(state) {
    return {
      phoneNumber: state.phoneNumber,
      hasCallback: Boolean(state.replyCallback),
    };
  },

  async receive(input, { send }) {
    const phoneNumber = input.target.phoneNumber;
    return send(input.message, {
      auth: input.auth,
      continuationToken: tokenFor(phoneNumber),
      state: {
        phoneNumber,
        replyCallback: null,
        pendingButtons: null,
        pendingImageUrl: null,
      },
      title: `WhatsApp ${phoneNumber}`,
    });
  },

  routes: [
    POST("/webhook", async (req, { send, waitUntil }) => {
      const body = (await req.json()) as WassistWebhookPayload;
      const phoneNumber = body.phone_number;
      if (!phoneNumber) {
        return Response.json({ error: "phone_number required" }, { status: 400 });
      }

      const text = (body.message ?? "").trim();
      const imageUrl = body.image ?? null;
      const replyCallback = body.reply_callback ?? null;

      const preface = [
        `[patient_phone=${phoneNumber}]`,
        body.conversation_id
          ? `[conversation_id=${body.conversation_id}]`
          : null,
        imageUrl ? `[meal_image_url=${imageUrl}]` : null,
        text || (imageUrl ? "I sent a photo of my meal." : "Hi"),
      ]
        .filter(Boolean)
        .join("\n");

      const content = imageUrl
        ? [
            { type: "text" as const, text: preface },
            {
              type: "file" as const,
              data: new URL(imageUrl),
              mediaType: "image/jpeg",
            },
          ]
        : preface;

      waitUntil(
        send(content, {
          auth: {
            authenticator: "wassist",
            principalType: "user",
            principalId: phoneNumber,
            attributes: {
              phoneNumber,
              replyCallback: replyCallback ?? "",
              conversationId: body.conversation_id ?? "",
            },
          },
          continuationToken: tokenFor(phoneNumber),
          state: {
            phoneNumber,
            replyCallback,
            pendingButtons: null,
            pendingImageUrl: null,
          },
          title: `WhatsApp ${phoneNumber}`,
        }).then(() => undefined),
      );

      return Response.json({ content: "No CUSTOMER message reply" });
    }),

    GET("/health", async () =>
      Response.json({
        ok: true,
        service: "steadfast-wassist",
        webhook: "/eve/v1/wassist/webhook",
      }),
    ),
  ],

  events: {
    "action.result"(eventData, channel) {
      const choices = toolResultFrom(eventData.result, offerChoices);
      if (choices?.output?.buttons?.length) {
        channel.state.pendingButtons = choices.output.buttons;
      }

      const meal = toolResultFrom(eventData.result, generateMealVisual);
      if (meal?.output?.imageUrl) {
        channel.state.pendingImageUrl = meal.output.imageUrl;
      }
    },

    async "message.completed"(eventData, channel) {
      if (eventData.finishReason === "tool-calls") return;

      const text =
        typeof eventData.message === "string"
          ? eventData.message.trim()
          : "";
      if (!text) return;

      const replyCallback = channel.state.replyCallback;
      if (!replyCallback) {
        console.warn("[wassist] no reply_callback; dropping outbound", {
          phoneNumber: channel.state.phoneNumber,
        });
        return;
      }

      const buttons = channel.state.pendingButtons;
      const imageUrl = channel.state.pendingImageUrl;
      channel.state.pendingButtons = null;
      channel.state.pendingImageUrl = null;

      try {
        await sendViaCallback(replyCallback, {
          content: text,
          ...(buttons?.length ? { buttons } : {}),
          ...(imageUrl ? { imageUrl } : {}),
        });
      } catch (err) {
        console.error("[wassist] reply_callback failed", err);
      }
    },
  },
});

type RunwareResult = {
  imageURL?: string;
  imageUrl?: string;
};

/**
 * Generate a personalized "upgraded meal" visual via Runware FLUX.
 */
export async function generateMealUpgradeImage(opts: {
  mealDescription: string;
  proteinTargetG: number;
  currentProteinG: number;
  diet?: string | null;
}): Promise<string> {
  const apiKey = process.env.RUNWARE_API_KEY;
  if (!apiKey) {
    throw new Error("RUNWARE_API_KEY is not set");
  }

  const dietLine = opts.diet
    ? `Respect a ${opts.diet} diet.`
    : "Keep the meal style consistent with the description.";

  const prompt = [
    "Photorealistic top-down photo of the same lunch plate,",
    `upgraded to hit about ${opts.proteinTargetG}g protein (was ~${opts.currentProteinG}g).`,
    `Meal context: ${opts.mealDescription}.`,
    dietLine,
    "Natural lighting, appetizing, no text overlay, no logos.",
  ].join(" ");

  const taskUUID = crypto.randomUUID();
  const res = await fetch(process.env.RUNWARE_API_URL ?? "https://api.runware.ai/v1", {
    method: "POST",
    headers: {
      Authorization: `Bearer ${apiKey}`,
      "Content-Type": "application/json",
    },
    body: JSON.stringify([
      {
        taskType: "imageInference",
        taskUUID,
        model: process.env.RUNWARE_MODEL ?? "runware:400@1",
        positivePrompt: prompt,
        width: 1024,
        height: 1024,
        deliveryMethod: "sync",
        numberResults: 1,
      },
    ]),
  });

  if (!res.ok) {
    const text = await res.text().catch(() => "");
    throw new Error(`Runware failed (${res.status}): ${text}`);
  }

  const json = (await res.json()) as
    | { data?: RunwareResult[] }
    | RunwareResult[]
    | { imageURL?: string };

  const rows = Array.isArray(json)
    ? json
    : "data" in json && Array.isArray(json.data)
      ? json.data
      : [json as RunwareResult];

  const url = rows[0]?.imageURL ?? rows[0]?.imageUrl;
  if (!url) {
    throw new Error("Runware response missing imageURL");
  }
  return url;
}

import { defineState } from "eve/context";

export type DropoutRisk = "low" | "medium" | "high";
export type OnboardingStatus = "not_started" | "in_progress" | "complete";

export type CheckIn = {
  at: string;
  sideEffectSeverity?: number;
  missedDoses?: number;
  notes?: string;
  mood?: string;
  proteinEstimateG?: number;
  resistanceSessions?: number;
};

export type EscalationCard = {
  id: string;
  phoneNumber: string;
  patientName: string;
  week: number | null;
  dose: string | null;
  risk: DropoutRisk;
  urgency: "routine" | "urgent" | "emergency";
  summary: string;
  transcriptSnippet: string;
  redFlag: string;
  status: "open" | "notified";
  createdAt: string;
  updatedAt: string;
};

export type Patient = {
  phoneNumber: string;
  onboardingStatus: OnboardingStatus;
  name: string | null;
  week: number | null;
  dose: string | null;
  medication: string | null;
  diet: string | null;
  proteinTargetG: number | null;
  motivation: string | null;
  sideEffectHistory: string[];
  checkins: CheckIn[];
  dropoutRisk: DropoutRisk;
  escalations: EscalationCard[];
  conversationId?: string;
  createdAt: string;
  updatedAt: string;
};

function now() {
  return new Date().toISOString();
}

function blankPatient(): Patient {
  const ts = now();
  return {
    phoneNumber: "",
    onboardingStatus: "not_started",
    name: null,
    week: null,
    dose: null,
    medication: null,
    diet: null,
    proteinTargetG: null,
    motivation: null,
    sideEffectHistory: [],
    checkins: [],
    dropoutRisk: "low",
    escalations: [],
    createdAt: ts,
    updatedAt: ts,
  };
}

/**
 * Durable per-WhatsApp-session patient record (Eve workflow state).
 * Sessions are keyed by phone via the Wassist channel continuation token.
 */
export const patientState = defineState("steadfast.patient", blankPatient);

export function getPatient(phoneNumber: string): Patient {
  const current = patientState.get();
  if (!current.phoneNumber) {
    patientState.update(() => ({
      ...blankPatient(),
      phoneNumber,
      createdAt: now(),
      updatedAt: now(),
    }));
    return patientState.get();
  }
  if (current.phoneNumber !== phoneNumber) {
    patientState.update(() => ({
      ...blankPatient(),
      phoneNumber,
      createdAt: now(),
      updatedAt: now(),
    }));
    return patientState.get();
  }
  return current;
}

export function updatePatient(phoneNumber: string, patch: Partial<Patient>): Patient {
  getPatient(phoneNumber);
  patientState.update((p) => ({
    ...p,
    ...patch,
    phoneNumber,
    updatedAt: now(),
  }));
  return patientState.get();
}

export function addCheckIn(phoneNumber: string, checkin: CheckIn): Patient {
  getPatient(phoneNumber);
  patientState.update((p) => ({
    ...p,
    checkins: [...p.checkins, checkin],
    updatedAt: now(),
  }));
  return patientState.get();
}

export function createEscalation(
  input: Omit<EscalationCard, "id" | "createdAt" | "updatedAt" | "status">,
): EscalationCard {
  const ts = now();
  const card: EscalationCard = {
    ...input,
    id: crypto.randomUUID(),
    status: "open",
    createdAt: ts,
    updatedAt: ts,
  };
  getPatient(input.phoneNumber);
  patientState.update((p) => ({
    ...p,
    escalations: [...p.escalations, card],
    updatedAt: ts,
  }));
  return card;
}

export function computeRiskScore(patient: Patient): DropoutRisk {
  const latest = patient.checkins[patient.checkins.length - 1];
  let score = 0;
  if (latest?.missedDoses && latest.missedDoses > 0) score += 2;
  if ((latest?.sideEffectSeverity ?? 0) >= 7) score += 2;
  else if ((latest?.sideEffectSeverity ?? 0) >= 4) score += 1;
  if ((latest?.notes ?? "").toLowerCase().includes("stop")) score += 2;
  if ((latest?.notes ?? "").toLowerCase().includes("cost")) score += 1;
  if (patient.week != null && patient.week >= 12 && patient.week <= 24) score += 1;
  if (score >= 4) return "high";
  if (score >= 2) return "medium";
  return "low";
}

export function missingOnboardingFields(patient: Patient): string[] {
  const missing: string[] = [];
  if (!patient.name) missing.push("name");
  if (!patient.medication) missing.push("medication");
  if (!patient.dose) missing.push("dose");
  if (patient.week == null) missing.push("week");
  if (!patient.diet) missing.push("diet");
  if (patient.proteinTargetG == null) missing.push("proteinTargetG");
  return missing;
}

export type WassistWebhookPayload = {
  message?: string | null;
  image?: string | null;
  phone_number: string;
  reply_callback?: string | null;
  conversation_id?: string | null;
};

export type QuickReplyButton = {
  type: "quick_reply";
  text: string;
  quickReplyId: string;
};

export type WassistOutbound = {
  content: string;
  imageUrl?: string;
  buttons?: QuickReplyButton[];
};

function buildBody(payload: WassistOutbound) {
  if (payload.buttons?.length || payload.imageUrl) {
    return {
      type: "unified",
      unified: {
        text: payload.content,
        ...(payload.imageUrl
          ? { media: { url: payload.imageUrl } }
          : {}),
        ...(payload.buttons?.length
          ? {
              buttons: payload.buttons.slice(0, 3).map((b) => ({
                type: "quick_reply" as const,
                text: b.text.slice(0, 20),
                quickReplyId: b.quickReplyId.slice(0, 200),
              })),
            }
          : {}),
      },
    };
  }
  return { type: "message", content: payload.content };
}

/**
 * Deliver via reply_callback (valid ~24h from user's last message).
 */
export async function sendViaCallback(
  replyCallback: string,
  payload: WassistOutbound,
): Promise<void> {
  const res = await fetch(replyCallback, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify(buildBody(payload)),
  });

  if (!res.ok) {
    // Fallback: plain content if unified shape is rejected by sandbox.
    if (payload.buttons?.length || payload.imageUrl) {
      const fallback = await fetch(replyCallback, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          content: payload.content,
          ...(payload.imageUrl ? { image: payload.imageUrl } : {}),
        }),
      });
      if (fallback.ok) return;
      const text = await fallback.text().catch(() => "");
      throw new Error(`Wassist callback failed (${fallback.status}): ${text}`);
    }
    const text = await res.text().catch(() => "");
    throw new Error(`Wassist callback failed (${res.status}): ${text}`);
  }
}

export async function sendViaRest(opts: {
  conversationId: string;
  content: string;
  imageUrl?: string;
  buttons?: QuickReplyButton[];
}): Promise<void> {
  const apiKey = process.env.WASSIST_API_KEY;
  if (!apiKey) {
    throw new Error("WASSIST_API_KEY is not set");
  }

  const base = process.env.WASSIST_API_BASE ?? "https://backend.wassist.app/api/v1";
  const body =
    opts.buttons?.length || opts.imageUrl
      ? {
          type: "unified",
          unified: {
            text: opts.content,
            ...(opts.imageUrl ? { media: { url: opts.imageUrl } } : {}),
            ...(opts.buttons?.length
              ? {
                  buttons: opts.buttons.slice(0, 3).map((b) => ({
                    type: "quick_reply" as const,
                    text: b.text.slice(0, 20),
                    quickReplyId: b.quickReplyId.slice(0, 200),
                  })),
                }
              : {}),
          },
        }
      : { type: "text", text: { body: opts.content } };

  const res = await fetch(`${base}/conversations/${opts.conversationId}/messages/`, {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      "X-API-Key": apiKey,
    },
    body: JSON.stringify(body),
  });

  if (!res.ok) {
    const text = await res.text().catch(() => "");
    throw new Error(`Wassist REST send failed (${res.status}): ${text}`);
  }
}

export type WassistConversation = {
  id: string;
  number?: string;
  phone_number?: string;
  status?: string;
};

export async function listConversations(): Promise<WassistConversation[]> {
  const apiKey = process.env.WASSIST_API_KEY;
  if (!apiKey) return [];
  const base = process.env.WASSIST_API_BASE ?? "https://backend.wassist.app/api/v1";
  const res = await fetch(`${base}/conversations/`, {
    headers: { "X-API-Key": apiKey },
  });
  if (!res.ok) {
    const text = await res.text().catch(() => "");
    throw new Error(`Wassist list conversations failed (${res.status}): ${text}`);
  }
  const json = (await res.json()) as WassistConversation[] | { results?: WassistConversation[] };
  return Array.isArray(json) ? json : (json.results ?? []);
}

