import { defineSchedule } from "eve/schedules";
import wassist from "../channels/wassist";
import { listConversations, sendViaRest } from "#lib/wassist";

/**
 * Proactive weekly check-in for active Wassist conversations.
 * Cron: Mondays 09:00 UTC
 */
export default defineSchedule({
  cron: "0 9 * * 1",
  async run({ receive, waitUntil, appAuth }) {
    if (!process.env.WASSIST_API_KEY) return;

    let conversations: Awaited<ReturnType<typeof listConversations>> = [];
    try {
      conversations = await listConversations();
    } catch (err) {
      console.error("[weekly_checkin] listConversations failed", err);
      return;
    }

    for (const conv of conversations) {
      const phone = conv.number ?? conv.phone_number;
      if (!phone || !conv.id) continue;

      const message =
        "Hi — it's your Steadfast weekly check-in. How has your GLP-1 week been? Any side effects, missed doses, or questions?";

      waitUntil(
        sendViaRest({
          conversationId: conv.id,
          content: message,
        })
          .then(() =>
            receive(wassist, {
              message: `[system] Weekly check-in nudge delivered to ${phone}. Await their reply; do not message again until they respond.`,
              target: { phoneNumber: phone },
              auth: appAuth,
            }),
          )
          .then(() => undefined)
          .catch((err) => {
            console.error("[weekly_checkin] failed", phone, err);
          }),
      );
    }
  },
});

import { defineAgent } from "eve";

export default defineAgent({
  description:
    "Draft a concise clinician escalation card from a patient transcript when red-flag symptoms appear. Does not message the patient.",
  model: process.env.EVE_MODEL ?? "openai/gpt-5.4-mini",
});

import { disableTool } from "eve/tools";

// Health coach must not run shell commands.
export default disableTool();

import { defineTool } from "eve/tools";
import { z } from "zod";
import { computeRiskScore, getPatient, updatePatient } from "#lib/store";

export default defineTool({
  description:
    "Recompute dropout risk (low/medium/high) from check-in signals after onboarding.",
  inputSchema: z.object({
    phoneNumber: z.string(),
  }),
  async execute({ phoneNumber }) {
    const patient = getPatient(phoneNumber);
    if (patient.onboardingStatus !== "complete") {
      throw new Error("Onboarding incomplete — finish onboarding first");
    }
    const risk = computeRiskScore(patient);
    updatePatient(phoneNumber, { dropoutRisk: risk });
    return {
      phoneNumber,
      name: patient.name,
      week: patient.week,
      dropoutRisk: risk,
      rationale:
        risk === "high"
          ? "Multiple churn signals — increase touchpoints and consider human coach outreach."
          : risk === "medium"
            ? "Some churn signals — stay close this week."
            : "Stable engagement — continue weekly ritual.",
    };
  },
});

import { defineTool } from "eve/tools";
import { z } from "zod";
import { createEscalation, getPatient } from "#lib/store";

export default defineTool({
  description:
    "Escalate a red-flag symptom to the human clinical team. Call immediately on severe abdominal pain, persistent vomiting, chest pain, allergic reaction, self-harm ideation, or similar.",
  inputSchema: z.object({
    phoneNumber: z.string(),
    redFlag: z.string(),
    summary: z.string(),
    transcriptSnippet: z.string(),
    urgency: z.enum(["routine", "urgent", "emergency"]).default("urgent"),
  }),
  async execute({ phoneNumber, redFlag, summary, transcriptSnippet, urgency }) {
    const patient = getPatient(phoneNumber);
    const card = createEscalation({
      phoneNumber,
      patientName: patient.name ?? "Unknown",
      week: patient.week,
      dose:
        patient.medication && patient.dose
          ? `${patient.medication} ${patient.dose}`
          : patient.medication ?? patient.dose,
      risk: patient.dropoutRisk,
      urgency,
      summary,
      transcriptSnippet,
      redFlag,
    });

    return {
      escalated: true,
      escalationId: card.id,
      messageForPatient:
        "I'm not able to assess this, and it sounds important — I'm connecting you with the clinical team right now.",
    };
  },
});

import { generateText } from "ai";
import { defineTool } from "eve/tools";
import { z } from "zod";
import { getPatient } from "#lib/store";

export default defineTool({
  description:
    "Estimate protein (and fibre) grams from a meal photo URL using vision. Use when the patient sends a lunch/dinner image.",
  inputSchema: z.object({
    phoneNumber: z.string(),
    imageUrl: z.string().url(),
    mealDescriptionHint: z.string().optional(),
  }),
  async execute({ phoneNumber, imageUrl, mealDescriptionHint }) {
    const patient = getPatient(phoneNumber);
    if (patient.proteinTargetG == null) {
      throw new Error(
        "Protein target not set — finish onboarding (proteinTargetG) before estimating meals",
      );
    }

    const dietNote = patient.diet ? `Diet: ${patient.diet}.` : "";

    const { text } = await generateText({
      model: process.env.EVE_VISION_MODEL ?? "openai/gpt-5.4-mini",
      messages: [
        {
          role: "user",
          content: [
            {
              type: "text",
              text: [
                "Estimate the protein and fibre content of this meal in grams.",
                dietNote,
                "Patient is on a GLP-1 programme.",
                mealDescriptionHint ? `Hint: ${mealDescriptionHint}` : "",
                'Reply ONLY as JSON: {"proteinG":number,"fibreG":number,"description":string,"confidence":"low"|"medium"|"high"}',
              ]
                .filter(Boolean)
                .join(" "),
            },
            { type: "image", image: new URL(imageUrl) },
          ],
        },
      ],
    });

    const jsonMatch = text.match(/\{[\s\S]*\}/);
    if (!jsonMatch) {
      throw new Error("Vision model did not return JSON protein estimate");
    }

    const parsed = JSON.parse(jsonMatch[0]) as {
      proteinG?: number;
      fibreG?: number;
      description?: string;
      confidence?: string;
    };

    const proteinG = Number(parsed.proteinG);
    if (!Number.isFinite(proteinG)) {
      throw new Error("Invalid proteinG from vision model");
    }

    return {
      proteinG,
      fibreG: Number(parsed.fibreG ?? 0),
      description: parsed.description ?? "meal from photo",
      confidence: parsed.confidence ?? "medium",
      proteinTargetG: patient.proteinTargetG,
      gapG: Math.max(0, patient.proteinTargetG - proteinG),
    };
  },
});

import { defineTool } from "eve/tools";
import { z } from "zod";
import { generateMealUpgradeImage } from "#lib/runware";
import { getPatient } from "#lib/store";

export default defineTool({
  description:
    "Generate a personalized higher-protein meal visual via Runware. The image attaches to your next WhatsApp reply. Requires onboarding protein target + RUNWARE_API_KEY.",
  inputSchema: z.object({
    phoneNumber: z.string(),
    mealDescription: z.string(),
    currentProteinG: z.number(),
  }),
  async execute({ phoneNumber, mealDescription, currentProteinG }) {
    const patient = getPatient(phoneNumber);
    if (patient.proteinTargetG == null) {
      throw new Error(
        "Protein target not set — finish onboarding before generating meal visuals",
      );
    }

    const url = await generateMealUpgradeImage({
      mealDescription,
      proteinTargetG: patient.proteinTargetG,
      currentProteinG,
      diet: patient.diet,
    });

    return {
      imageUrl: url,
      caption: `Here's your plate upgraded toward ~${patient.proteinTargetG}g protein.`,
      generated: true,
      note: "Image attaches to your next WhatsApp message this turn.",
    };
  },
});

import { defineTool } from "eve/tools";
import { z } from "zod";
import { getPatient, missingOnboardingFields, updatePatient } from "#lib/store";

export default defineTool({
  description:
    "Load the patient's profile and onboarding status. Call at the start of every turn before coaching or onboarding.",
  inputSchema: z.object({
    phoneNumber: z.string().describe("WhatsApp phone in E.164 form"),
    conversationId: z
      .string()
      .optional()
      .describe("Wassist conversation id if present in the user message"),
  }),
  async execute({ phoneNumber, conversationId }) {
    let p = getPatient(phoneNumber);
    if (conversationId && p.conversationId !== conversationId) {
      p = updatePatient(phoneNumber, { conversationId });
    }
    const missing = missingOnboardingFields(p);
    return {
      phoneNumber: p.phoneNumber,
      onboardingStatus: p.onboardingStatus,
      onboardingComplete: missing.length === 0 && p.onboardingStatus === "complete",
      missingOnboardingFields: missing,
      name: p.name,
      week: p.week,
      dose: p.dose,
      medication: p.medication,
      diet: p.diet,
      proteinTargetG: p.proteinTargetG,
      motivation: p.motivation,
      sideEffectHistory: p.sideEffectHistory,
      dropoutRisk: p.dropoutRisk,
      recentCheckins: p.checkins.slice(-3),
      openEscalations: p.escalations.filter((e) => e.status === "open").length,
    };
  },
});

import { defineTool } from "eve/tools";
import { z } from "zod";
import { addCheckIn, computeRiskScore, getPatient, updatePatient } from "#lib/store";

export default defineTool({
  description:
    "Persist a structured weekly check-in after onboarding is complete. Updates dropout risk.",
  inputSchema: z.object({
    phoneNumber: z.string(),
    sideEffectSeverity: z.number().min(0).max(10).optional(),
    missedDoses: z.number().min(0).max(7).optional(),
    mood: z.string().optional(),
    notes: z.string().optional(),
    proteinEstimateG: z.number().optional(),
    resistanceSessions: z.number().optional(),
  }),
  async execute(input) {
    const existing = getPatient(input.phoneNumber);
    if (existing.onboardingStatus !== "complete") {
      throw new Error("Onboarding incomplete — finish onboarding before logging check-ins");
    }

    const checkin = {
      at: new Date().toISOString(),
      sideEffectSeverity: input.sideEffectSeverity,
      missedDoses: input.missedDoses,
      mood: input.mood,
      notes: input.notes,
      proteinEstimateG: input.proteinEstimateG,
      resistanceSessions: input.resistanceSessions,
    };
    const patient = addCheckIn(input.phoneNumber, checkin);
    const risk = computeRiskScore(patient);
    updatePatient(input.phoneNumber, { dropoutRisk: risk });
    return {
      logged: true,
      dropoutRisk: risk,
      checkinCount: patient.checkins.length,
    };
  },
});

import { defineTool } from "eve/tools";
import { z } from "zod";
import { getPatient } from "#lib/store";

/**
 * Queue WhatsApp quick-reply buttons on the next outbound coach message.
 * Max 3 buttons (WhatsApp limit).
 */
export default defineTool({
  description:
    "Attach up to 3 WhatsApp quick-reply buttons to your NEXT text reply. Call this in the same turn before you finish speaking when offering choices (diet type, protein band, yes/no). Do not dump long option lists in text if buttons cover them.",
  inputSchema: z.object({
    phoneNumber: z.string(),
    choices: z
      .array(
        z.object({
          label: z.string().max(20).describe("Button label shown on WhatsApp"),
          id: z
            .string()
            .max(200)
            .describe("Stable id when tapped, e.g. diet_vegetarian"),
        }),
      )
      .min(1)
      .max(3),
  }),
  async execute({ phoneNumber, choices }) {
    // Ensures durable patient session exists for this phone.
    getPatient(phoneNumber);
    const buttons = choices.map((c) => ({
      type: "quick_reply" as const,
      text: c.label.slice(0, 20),
      quickReplyId: c.id.slice(0, 200),
    }));
    return {
      queued: true,
      buttonCount: buttons.length,
      buttons,
      note: "Buttons attach to your next WhatsApp message this turn.",
    };
  },
});

import { defineTool } from "eve/tools";
import { z } from "zod";
import {
  getPatient,
  missingOnboardingFields,
  updatePatient,
} from "#lib/store";

export default defineTool({
  description:
    "Save onboarding answers from WhatsApp (name, medication, dose, week, diet, protein target, motivation). Call after each answer or batch when several arrive. Marks onboarding complete when all required fields are present.",
  inputSchema: z.object({
    phoneNumber: z.string(),
    conversationId: z.string().optional(),
    name: z.string().min(1).optional(),
    medication: z
      .string()
      .optional()
      .describe("e.g. semaglutide, tirzepatide, oral Wegovy, orforglipron"),
    dose: z.string().optional().describe("e.g. 0.25mg, 1mg, 12.5mg"),
    week: z.number().int().min(0).max(104).optional(),
    diet: z
      .string()
      .optional()
      .describe("e.g. omnivore, vegetarian, vegan, other"),
    proteinTargetG: z
      .number()
      .int()
      .min(40)
      .max(250)
      .optional()
      .describe("Daily protein target in grams"),
    motivation: z.string().optional(),
    sideEffectNote: z.string().optional(),
  }),
  async execute(input) {
    const patch: Parameters<typeof updatePatient>[1] = {
      onboardingStatus: "in_progress",
    };
    if (input.conversationId) patch.conversationId = input.conversationId;
    if (input.name !== undefined) patch.name = input.name.trim();
    if (input.medication !== undefined) patch.medication = input.medication.trim();
    if (input.dose !== undefined) patch.dose = input.dose.trim();
    if (input.week !== undefined) patch.week = input.week;
    if (input.diet !== undefined) patch.diet = input.diet.trim();
    if (input.proteinTargetG !== undefined) patch.proteinTargetG = input.proteinTargetG;
    if (input.motivation !== undefined) patch.motivation = input.motivation.trim();

    let patient = updatePatient(input.phoneNumber, patch);

    if (input.sideEffectNote?.trim()) {
      patient = updatePatient(input.phoneNumber, {
        sideEffectHistory: [
          ...patient.sideEffectHistory,
          input.sideEffectNote.trim(),
        ],
      });
    }

    const missing = missingOnboardingFields(patient);
    if (missing.length === 0) {
      patient = updatePatient(input.phoneNumber, {
        onboardingStatus: "complete",
      });
    }

    return {
      onboardingStatus: patient.onboardingStatus,
      missingOnboardingFields: missing,
      profile: {
        name: patient.name,
        medication: patient.medication,
        dose: patient.dose,
        week: patient.week,
        diet: patient.diet,
        proteinTargetG: patient.proteinTargetG,
        motivation: patient.motivation,
      },
    };
  },
});

